// Shared semaphore variable
SEMAPHORE mutex = 1;

// Wait operation (P)
wait(SEMAPHORE S):
 S = S - 1;
 if S < 0:
 block this process
 add to waiting queue

// Signal operation (V)
signal(SEMAPHORE S):
 S = S + 1;
 if S <= 0:
 wake up one process from waiting queue

// Process using semaphore
process P:
 while true:
 wait(mutex); // Entry section
 // Critical section
 critical_code();
 signal(mutex); // Exit section
 // Remainder section

// Constants and variables
N = 10; // Buffer size
buffer[N];
in = 0, out = 0;

// Semaphores
SEMAPHORE empty = N; // Count of empty slots
SEMAPHORE full = 0; // Count of filled slots
SEMAPHORE mutex = 1; // For mutual exclusion

// Producer Process
producer():
 while true:
 item = produce();
 wait(empty); // Wait for empty slot
 wait(mutex); // Enter critical section
 buffer[in] = item;
 in = (in + 1) % N;
 signal(mutex); // Exit critical section
 signal(full); // Signal filled slot

// Consumer Process
consumer():
 while true:
 wait(full); // Wait for filled slot
 wait(mutex); // Enter critical section
 item = buffer[out];
 out = (out + 1) % N;
 signal(mutex); // Exit critical section
 signal(empty); // Signal empty slot
 consume(item);

// Shared variables
SEMAPHORE mutex = 1; // Protects readcount
SEMAPHORE wrt = 1; // Writers need exclusive access
int readcount = 0;

// Reader Process
reader():
 while true:
 wait(mutex);
 readcount = readcount + 1;
 if readcount == 1:
 wait(wrt); // First reader locks writers out
 signal(mutex);

 // Reading happens here - multiple readers allowed
 read_data();

 wait(mutex);
 readcount = readcount - 1;
 if readcount == 0:
 signal(wrt); // Last reader releases writers
 signal(mutex);

// Writer Process
writer():
 while true:
 wait(wrt); // Get exclusive access
 write_data(); // Only one writer at a time
 signal(wrt);
